<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Helix — Distributed Tracing for Streaming Pipelines</title>
<style>
  *,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
  :root{
    --bg:#0a0c12;--bg2:#111827;--bg3:#1a1f2e;--bg4:#242b3d;
    --text:#e2e8f0;--text2:#94a3b8;--text3:#64748b;
    --cyan:#06b6d4;--cyan2:#22d3ee;--cyan-glow:rgba(6,182,212,.15);
    --green:#10b981;--amber:#f59e0b;--red:#ef4444;
    --font:-apple-system,BlinkMacSystemFont,"Segoe UI",Roboto,Helvetica,Arial,sans-serif;
    --mono:"SF Mono","Fira Code","Cascadia Code",Consolas,monospace;
    --nav-h:64px;
  }
  html{scroll-behavior:smooth;font-size:16px}
  body{font-family:var(--font);background:var(--bg);color:var(--text);line-height:1.6;overflow-x:hidden}
  a{color:var(--cyan);text-decoration:none;transition:color .2s}
  a:hover{color:var(--cyan2)}
  .container{max-width:1200px;margin:0 auto;padding:0 24px}

  /* ── NAV ── */
  nav{position:sticky;top:0;z-index:100;background:rgba(10,12,18,.85);backdrop-filter:blur(16px);border-bottom:1px solid rgba(255,255,255,.06);height:var(--nav-h);display:flex;align-items:center}
  .nav-inner{display:flex;align-items:center;justify-content:space-between;width:100%;max-width:1200px;margin:0 auto;padding:0 24px}
  .logo{display:flex;align-items:center;gap:10px;font-size:1.25rem;font-weight:700;color:#fff;letter-spacing:-.02em}
  .logo svg{width:32px;height:32px}
  .nav-links{display:flex;align-items:center;gap:32px}
  .nav-links a{font-size:.875rem;color:var(--text2);font-weight:500;transition:color .2s}
  .nav-links a:hover{color:#fff}
  .btn{display:inline-flex;align-items:center;justify-content:center;padding:10px 22px;border-radius:8px;font-size:.875rem;font-weight:600;border:none;cursor:pointer;transition:all .2s;text-decoration:none}
  .btn-primary{background:var(--cyan);color:#0a0c12}
  .btn-primary:hover{background:var(--cyan2);transform:translateY(-1px);box-shadow:0 4px 24px rgba(6,182,212,.3)}
  .btn-secondary{background:transparent;color:var(--text);border:1px solid var(--bg4)}
  .btn-secondary:hover{border-color:var(--cyan);color:var(--cyan)}
  .btn-sm{padding:8px 18px;font-size:.813rem}

  /* ── HERO ── */
  .hero{padding:100px 0 80px;position:relative;overflow:hidden}
  .hero::before{content:'';position:absolute;top:-200px;left:50%;transform:translateX(-50%);width:900px;height:600px;background:radial-gradient(ellipse,rgba(6,182,212,.08) 0%,transparent 70%);pointer-events:none}
  .hero-grid{display:grid;grid-template-columns:1fr 1fr;gap:64px;align-items:center}
  .hero h1{font-size:3.5rem;font-weight:800;line-height:1.1;letter-spacing:-.03em;color:#fff;margin-bottom:20px}
  .hero h1 span{background:linear-gradient(135deg,var(--cyan),#818cf8);-webkit-background-clip:text;-webkit-text-fill-color:transparent;background-clip:text}
  .hero-sub{font-size:1.125rem;color:var(--text2);margin-bottom:36px;max-width:480px;line-height:1.7}
  .hero-ctas{display:flex;gap:16px;flex-wrap:wrap}
  .hero-ctas .btn{padding:14px 28px;font-size:1rem}
  .hero-meta{margin-top:24px;font-size:.813rem;color:var(--text3);display:flex;align-items:center;gap:16px}
  .hero-meta span{display:flex;align-items:center;gap:6px}
  .hero-meta svg{width:14px;height:14px;fill:var(--green)}

  /* ── TERMINAL ── */
  .terminal-wrap{position:relative}
  .terminal{background:#0d1117;border:1px solid rgba(255,255,255,.08);border-radius:12px;overflow:hidden;box-shadow:0 20px 60px rgba(0,0,0,.5),0 0 40px rgba(6,182,212,.06);font-size:.75rem}
  .terminal-bar{display:flex;align-items:center;gap:8px;padding:12px 16px;background:rgba(255,255,255,.03);border-bottom:1px solid rgba(255,255,255,.06)}
  .terminal-dot{width:10px;height:10px;border-radius:50%}
  .terminal-dot:nth-child(1){background:#ff5f57}
  .terminal-dot:nth-child(2){background:#febc2e}
  .terminal-dot:nth-child(3){background:#28c840}
  .terminal-title{margin-left:12px;font-size:.688rem;color:var(--text3);font-family:var(--mono)}
  .terminal-body{padding:16px;max-height:380px;overflow:hidden;position:relative;font-family:var(--mono)}
  .terminal-body::after{content:'';position:absolute;bottom:0;left:0;right:0;height:60px;background:linear-gradient(transparent,#0d1117);pointer-events:none}
  .term-line{opacity:0;transform:translateY(8px);margin-bottom:4px;font-size:.75rem;line-height:1.6}
  .term-line.visible{opacity:1;transform:translateY(0);transition:all .3s ease}
  .t-time{color:var(--text3)}
  .t-level-info{color:var(--cyan)}
  .t-level-warn{color:var(--amber)}
  .t-level-ok{color:var(--green)}
  .t-key{color:#c084fc}
  .t-str{color:#86efac}
  .t-num{color:#fbbf24}
  .t-svc{color:var(--cyan2)}

  /* ── SECTION COMMON ── */
  section{padding:100px 0}
  .section-label{font-size:.75rem;font-weight:600;text-transform:uppercase;letter-spacing:.1em;color:var(--cyan);margin-bottom:12px}
  .section-title{font-size:2.25rem;font-weight:800;color:#fff;letter-spacing:-.02em;margin-bottom:16px}
  .section-desc{font-size:1.0625rem;color:var(--text2);max-width:560px;margin-bottom:56px}
  .text-center{text-align:center}
  .mx-auto{margin-left:auto;margin-right:auto}

  /* ── FEATURES ── */
  .features{background:var(--bg2);position:relative}
  .features::before{content:'';position:absolute;top:0;left:0;right:0;height:1px;background:linear-gradient(90deg,transparent,var(--cyan-glow),transparent)}
  .feat-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:32px}
  .feat-card{background:var(--bg);border:1px solid rgba(255,255,255,.06);border-radius:16px;padding:40px 32px;transition:all .3s ease;position:relative;overflow:hidden}
  .feat-card::before{content:'';position:absolute;top:0;left:0;right:0;height:2px;background:linear-gradient(90deg,var(--cyan),#818cf8);transform:scaleX(0);transform-origin:left;transition:transform .4s ease}
  .feat-card:hover{border-color:rgba(6,182,212,.2);transform:translateY(-4px);box-shadow:0 12px 40px rgba(0,0,0,.3)}
  .feat-card:hover::before{transform:scaleX(1)}
  .feat-icon{width:48px;height:48px;border-radius:12px;background:var(--cyan-glow);display:flex;align-items:center;justify-content:center;margin-bottom:24px}
  .feat-icon svg{width:24px;height:24px}
  .feat-card h3{font-size:1.1875rem;font-weight:700;color:#fff;margin-bottom:12px}
  .feat-card p{font-size:.9375rem;color:var(--text2);line-height:1.7}

  /* ── LOGOS ── */
  .logos-strip{padding:60px 0;border-top:1px solid rgba(255,255,255,.04);border-bottom:1px solid rgba(255,255,255,.04)}
  .logos-strip p{font-size:.813rem;color:var(--text3);text-align:center;margin-bottom:32px;text-transform:uppercase;letter-spacing:.08em;font-weight:500}
  .logos-row{display:flex;align-items:center;justify-content:center;gap:64px;flex-wrap:wrap;opacity:.6}
  .logos-row svg{height:32px;width:auto;transition:opacity .3s}
  .logos-row svg:hover{opacity:1.2}

  /* ── TOUR ── */
  .tour{position:relative}
  .tour-steps{display:flex;flex-direction:column;gap:0;max-width:900px;margin:0 auto;position:relative}
  .tour-steps::before{content:'';position:absolute;left:112px;top:0;bottom:0;width:2px;background:linear-gradient(var(--cyan),rgba(6,182,212,.1))}
  .tour-step{display:grid;grid-template-columns:112px 2px 1fr;gap:0;align-items:start;padding:0 0 64px 0;position:relative}
  .tour-step:last-child{padding-bottom:0}
  .tour-step-num{display:flex;flex-direction:column;align-items:center;justify-content:flex-start;padding-top:8px}
  .tour-step-dot{width:44px;height:44px;border-radius:50%;background:var(--bg);border:2px solid var(--cyan);display:flex;align-items:center;justify-content:center;font-size:.875rem;font-weight:700;color:var(--cyan);z-index:1;transition:all .3s}
  .tour-step:hover .tour-step-dot{background:var(--cyan);color:var(--bg);box-shadow:0 0 24px rgba(6,182,212,.4)}
  .tour-step-line{background:rgba(255,255,255,.06)}
  .tour-step-content{padding-left:32px}
  .tour-step-content h3{font-size:1.25rem;font-weight:700;color:#fff;margin-bottom:8px}
  .tour-step-content p{font-size:.9375rem;color:var(--text2);margin-bottom:24px;line-height:1.7}
  .tour-mock{background:var(--bg2);border:1px solid rgba(255,255,255,.06);border-radius:12px;padding:20px;overflow:hidden}
  .mock-bar{display:flex;gap:6px;margin-bottom:16px}
  .mock-dot{width:8px;height:8px;border-radius:50%;background:var(--bg4)}
  .mock-row{display:flex;align-items:center;gap:12px;padding:8px 0;border-bottom:1px solid rgba(255,255,255,.04)}
  .mock-row:last-child{border:none}
  .mock-tag{padding:3px 10px;border-radius:4px;font-size:.625rem;font-family:var(--mono);font-weight:600}
  .mock-tag.cyan{background:rgba(6,182,212,.15);color:var(--cyan)}
  .mock-tag.green{background:rgba(16,185,129,.15);color:var(--green)}
  .mock-tag.amber{background:rgba(245,158,11,.15);color:var(--amber)}
  .mock-tag.purple{background:rgba(168,85,247,.15);color:#a855f7}
  .mock-bar-h{height:8px;border-radius:4px;background:var(--bg4)}
  .mock-bar-h.fill{background:linear-gradient(90deg,var(--cyan),#818cf8)}
  .mock-text{font-size:.688rem;color:var(--text3);font-family:var(--mono)}
  .mock-timeline{display:flex;gap:2px;align-items:end;height:60px;margin-top:12px}
  .mock-bar-v{flex:1;border-radius:2px 2px 0 0;background:var(--cyan);opacity:.6;transition:opacity .3s}
  .mock-bar-v:hover{opacity:1}
  .mock-bar-v.warn{background:var(--amber)}
  .mock-bar-v.err{background:var(--red)}
  .mock-graph{position:relative;height:80px;margin-top:12px}
  .mock-graph svg{width:100%;height:100%}
  .mock-kv{display:grid;grid-template-columns:1fr 1fr;gap:8px;margin-top:12px}
  .mock-kv-item{background:var(--bg);border-radius:6px;padding:10px 12px}
  .mock-kv-item .k{font-size:.625rem;color:var(--text3);text-transform:uppercase;letter-spacing:.05em}
  .mock-kv-item .v{font-size:.875rem;color:#fff;font-weight:600;font-family:var(--mono);margin-top:2px}

  /* ── PRICING ── */
  .pricing{background:var(--bg2);position:relative}
  .pricing::before{content:'';position:absolute;top:0;left:0;right:0;height:1px;background:linear-gradient(90deg,transparent,var(--cyan-glow),transparent)}
  .pricing-card{max-width:700px;margin:0 auto;background:var(--bg);border:1px solid rgba(255,255,255,.06);border-radius:20px;padding:48px;text-align:center;position:relative;overflow:hidden}
  .pricing-card::before{content:'';position:absolute;top:-100px;left:50%;transform:translateX(-50%);width:400px;height:200px;background:radial-gradient(ellipse,rgba(6,182,212,.1),transparent);pointer-events:none}
  .pricing-price{font-size:3.5rem;font-weight:800;color:#fff;margin:16px 0 4px}
  .pricing-price span{font-size:1rem;font-weight:500;color:var(--text3)}
  .pricing-sub{color:var(--text2);font-size:.9375rem;margin-bottom:32px}
  .pricing-features{display:flex;flex-direction:column;gap:12px;text-align:left;max-width:360px;margin:0 auto 36px}
  .pricing-features li{list-style:none;display:flex;align-items:center;gap:12px;font-size:.9375rem;color:var(--text2)}
  .pricing-features li svg{width:18px;height:18px;flex-shrink:0}
  .pricing-link{display:inline-flex;align-items:center;gap:8px;color:var(--cyan);font-weight:600;font-size:1rem;transition:gap .2s}
  .pricing-link:hover{gap:12px}

  /* ── FOOTER ── */
  footer{padding:64px 0 32px;border-top:1px solid rgba(255,255,255,.06)}
  .footer-grid{display:grid;grid-template-columns:2fr 1fr 1fr 1fr 1fr;gap:48px;margin-bottom:48px}
  .footer-brand p{font-size:.875rem;color:var(--text3);margin-top:12px;line-height:1.7;max-width:280px}
  .footer-col h4{font-size:.75rem;text-transform:uppercase;letter-spacing:.1em;color:var(--text3);margin-bottom:16px;font-weight:600}
  .footer-col a{display:block;font-size:.875rem;color:var(--text2);padding:4px 0;transition:color .2s}
  .footer-col a:hover{color:var(--cyan)}
  .status-badge{display:inline-flex;align-items:center;gap:8px;padding:6px 14px;border-radius:20px;background:rgba(16,185,129,.1);border:1px solid rgba(16,185,129,.2);font-size:.75rem;color:var(--green);font-weight:500;margin-top:16px}
  .status-dot{width:6px;height:6px;border-radius:50%;background:var(--green);animation:pulse-dot 2s ease infinite}
  @keyframes pulse-dot{0%,100%{opacity:1}50%{opacity:.4}}
  .footer-bottom{display:flex;justify-content:space-between;align-items:center;padding-top:24px;border-top:1px solid rgba(255,255,255,.04);font-size:.813rem;color:var(--text3)}

  /* ── SCROLL ANIMATIONS ── */
  .reveal{opacity:0;transform:translateY(24px);transition:all .6s cubic-bezier(.16,1,.3,1)}
  .reveal.in{opacity:1;transform:translateY(0)}
  .reveal-d1{transition-delay:.1s}
  .reveal-d2{transition-delay:.2s}
  .reveal-d3{transition-delay:.3s}

  /* ── RESPONSIVE ── */
  @media(max-width:900px){
    .hero-grid{grid-template-columns:1fr;gap:40px}
    .hero h1{font-size:2.5rem}
    .feat-grid{grid-template-columns:1fr}
    .footer-grid{grid-template-columns:1fr 1fr}
    .tour-steps::before{left:24px}
    .tour-step{grid-template-columns:50px 2px 1fr}
    .tour-step-dot{width:36px;height:36px;font-size:.75rem}
    .tour-step-content{padding-left:16px}
    .logos-row{gap:32px}
  }
  @media(max-width:600px){
    .hero h1{font-size:2rem}
    .nav-links{display:none}
    .section-title{font-size:1.75rem}
    .pricing-card{padding:32px 24px}
    .pricing-price{font-size:2.5rem}
  }
</style>
</head>
<body>

<!-- ═══════════════ NAV ═══════════════ -->
<nav>
  <div class="nav-inner">
    <a href="#" class="logo">
      <svg viewBox="0 0 32 32" fill="none">
        <defs>
          <linearGradient id="hg" x1="0" y1="0" x2="32" y2="32">
            <stop offset="0%" stop-color="#06b6d4"/>
            <stop offset="100%" stop-color="#818cf8"/>
          </linearGradient>
        </defs>
        <path d="M16 2C16 2 6 10 6 16s10 14 10 14 10-8 10-14S16 2 16 2z" stroke="url(#hg)" stroke-width="2.5" fill="none"/>
        <path d="M16 6c0 0-6 5.5-6 10s6 10 6 10 6-5.5 6-10S16 6 16 6z" fill="url(#hg)" opacity=".2"/>
        <circle cx="16" cy="16" r="2.5" fill="url(#hg)"/>
      </svg>
      Helix
    </a>
    <div class="nav-links">
      <a href="#features">Features</a>
      <a href="#tour">Product</a>
      <a href="#pricing">Pricing</a>
      <a href="#">Docs</a>
      <a href="#demo" class="btn btn-primary btn-sm">Book a Demo</a>
    </div>
  </div>
</nav>

<!-- ═══════════════ HERO ═══════════════ -->
<section class="hero">
  <div class="container hero-grid">
    <div>
      <h1>Trace every event.<br><span>Across every hop.</span></h1>
      <p class="hero-sub">Helix instruments your streaming pipeline end-to-end — from ingest to sink — so you can find latency, duplicates, and dropped events in seconds, not postmortems.</p>
      <div class="hero-ctas">
        <a href="#demo" class="btn btn-primary">Book a Demo</a>
        <a href="#tour" class="btn btn-secondary">See How It Works</a>
      </div>
      <div class="hero-meta">
        <span><svg viewBox="0 0 16 16"><circle cx="8" cy="8" r="7" fill="var(--green)"/><path d="M5 8l2 2 4-4" stroke="#0a0c12" stroke-width="1.5" fill="none" stroke-linecap="round"/></svg> SOC 2 Type II</span>
        <span><svg viewBox="0 0 16 16"><circle cx="8" cy="8" r="7" fill="var(--green)"/><path d="M5 8l2 2 4-4" stroke="#0a0c12" stroke-width="1.5" fill="none" stroke-linecap="round"/></svg> &lt;50ms P99 overhead</span>
      </div>
    </div>
    <div class="terminal-wrap">
      <div class="terminal">
        <div class="terminal-bar">
          <span class="terminal-dot"></span>
          <span class="terminal-dot"></span>
          <span class="terminal-dot"></span>
          <span class="terminal-title">helix trace --follow pipeline=orders-events</span>
        </div>
        <div class="terminal-body" id="termBody"></div>
      </div>
    </div>
  </div>
</section>

<!-- ═══════════════ FEATURES ═══════════════ -->
<section class="features" id="features">
  <div class="container">
    <div class="text-center">
      <p class="section-label reveal">Why Teams Switch</p>
      <h2 class="section-title reveal reveal-d1">Built for the reality of streaming</h2>
      <p class="section-desc mx-auto reveal reveal-d2">Most tracing tools were designed for HTTP microservices. Helix understands Kafka topics, consumer groups, windowed aggregations, and exactly-once semantics.</p>
    </div>
    <div class="feat-grid">
      <!-- Card 1 -->
      <div class="feat-card reveal">
        <div class="feat-icon">
          <svg viewBox="0 0 24 24" fill="none" stroke="var(--cyan)" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round">
            <path d="M12 2v4M12 18v4M4.93 4.93l2.83 2.83M16.24 16.24l2.83 2.83M2 12h4M18 12h4M4.93 19.07l2.83-2.83M16.24 7.76l2.83-2.83"/>
            <circle cx="12" cy="12" r="3"/>
          </svg>
        </div>
        <h3>End-to-End Span Context</h3>
        <p>Automatic span injection across Kafka, Kinesis, and Pub/Sub — no SDK changes required. Every message carries its full lineage from producer to consumer group.</p>
      </div>
      <!-- Card 2 -->
      <div class="feat-card reveal reveal-d1">
        <div class="feat-icon">
          <svg viewBox="0 0 24 24" fill="none" stroke="var(--cyan)" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round">
            <rect x="2" y="3" width="20" height="14" rx="2"/>
            <path d="M8 21h8M12 17v4"/>
            <path d="M7 8h2v4H7zM11 10h2v2h-2zM15 8h2v4h-2z"/>
          </svg>
        </div>
        <h3>Sub-Second Root Cause</h3>
        <p>Correlate lag, retries, and poison pills across consumers in a single query. Our trace-graph engine indexes by topic, partition, and consumer group simultaneously.</p>
      </div>
      <!-- Card 3 -->
      <div class="feat-card reveal reveal-d2">
        <div class="feat-icon">
          <svg viewBox="0 0 24 24" fill="none" stroke="var(--cyan)" stroke-width="1.5" stroke-linecap="round" stroke-linejoin="round">
            <path d="M12 22c5.523 0 10-4.477 10-10S17.523 2 12 2 2 6.477 2 12s4.477 10 10 10z"/>
            <path d="M12 6v6l4 2"/>
            <path d="M2 12h2M20 12h2M12 2v2M12 20v2"/>
          </svg>
        </div>
        <h3>Latency Budgets &amp; Alerts</h3>
        <p>Set per-hop latency budgets that alert before SLAs breach. Helix distinguishes between processing delay, network jitter, and backpressure so you fix the right thing.</p>
      </div>
    </div>
  </div>
</section>

<!-- ═══════════════ LOGOS ═══════════════ -->
<div class="logos-strip">
  <div class="container">
    <p class="reveal">Trusted by data teams at</p>
    <div class="logos-row reveal reveal-d1">
      <!-- Logo 1: Streamline -->
      <svg viewBox="0 0 140 32" fill="none">
        <rect x="2" y="8" width="16" height="16" rx="3" fill="#06b6d4" opacity=".7"/>
        <rect x="22" y="4" width="4" height="24" rx="1" fill="#06b6d4"/>
        <text x="32" y="22" font-family="var(--font)" font-size="14" font-weight="700" fill="#e2e8f0">Streamline</text>
      </svg>
      <!-- Logo 2: DataForge -->
      <svg viewBox="0 0 130 32" fill="none">
        <path d="M6 6l8 10-8 10" stroke="#818cf8" stroke-width="2.5" fill="none" stroke-linecap="round"/>
        <path d="M16 6l-8 10 8 10" stroke="#818cf8" stroke-width="2.5" fill="none" stroke-linecap="round"/>
        <text x="26" y="22" font-family="var(--font)" font-size="14" font-weight="700" fill="#e2e8f0">DataForge</text>
      </svg>
      <!-- Logo 3: PipeOps -->
      <svg viewBox="0 0 110 32" fill="none">
        <circle cx="10" cy="16" r="6" stroke="#10b981" stroke-width="2" fill="none"/>
        <circle cx="22" cy="16" r="6" stroke="#10b981" stroke-width="2" fill="none"/>
        <line x1="16" y1="16" x2="16" y2="16" stroke="#10b981" stroke-width="2"/>
        <text x="32" y="22" font-family="var(--font)" font-size="14" font-weight="700" fill="#e2e8f0">PipeOps</text>
      </svg>
      <!-- Logo 4: Flowstate -->
      <svg viewBox="0 0 125 32" fill="none">
        <path d="M4 24c4-12 8-4 12-12s8 4 12-4" stroke="#f59e0b" stroke-width="2" fill="none" stroke-linecap="round"/>
        <text x="24" y="22" font-family="var(--font)" font-size="14" font-weight="700" fill="#e2e8f0">Flowstate</text>
      </svg>
