<style>
  *,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
  :root{
    --emerald:#10b981;--emerald-dark:#059669;--emerald-light:#d1fae5;--emerald-50:#ecfdf5;
    --bg:#f8fafc;--surface:#ffffff;--border:#e2e8f0;--text:#0f172a;--text-secondary:#64748b;
    --text-muted:#94a3b8;--red:#ef4444;--red-bg:#fef2f2;--amber:#f59e0b;--amber-bg:#fffbeb;
    --blue:#3b82f6;--blue-bg:#eff6ff;--sidebar-w:240px;--sidebar-collapsed:64px;--topbar-h:56px;
    --radius:8px;--radius-sm:6px;
  }
  html{font-size:14px}
  body{font-family:-apple-system,BlinkMacSystemFont,"Segoe UI",Roboto,"Helvetica Neue",Arial,sans-serif;
    background:var(--bg);color:var(--text);line-height:1.5;overflow-x:hidden}
  button{font:inherit;cursor:pointer;border:none;background:none;color:inherit}
  select,input{font:inherit;color:inherit}

  /* SIDEBAR */
  .sidebar{position:fixed;top:0;left:0;width:var(--sidebar-w);height:100vh;
    background:var(--surface);border-right:1px solid var(--border);z-index:100;
    display:flex;flex-direction:column;transition:width .25s ease;overflow:hidden}
  .sidebar.collapsed{width:var(--sidebar-collapsed)}
  .sidebar-brand{display:flex;align-items:center;gap:10px;padding:16px;height:var(--topbar-h);
    border-bottom:1px solid var(--border);flex-shrink:0;white-space:nowrap}
  .sidebar-brand .logo{width:28px;height:28px;background:var(--emerald);border-radius:6px;
    display:flex;align-items:center;justify-content:center;flex-shrink:0}
  .sidebar-brand .logo svg{width:18px;height:18px}
  .sidebar-brand span{font-weight:700;font-size:1.1rem;color:var(--text);opacity:1;
    transition:opacity .2s}
  .sidebar.collapsed .sidebar-brand span{opacity:0;pointer-events:none}
  .sidebar-nav{flex:1;padding:12px 8px;overflow-y:auto}
  .nav-item{display:flex;align-items:center;gap:12px;padding:10px 12px;border-radius:var(--radius-sm);
    color:var(--text-secondary);text-decoration:none;cursor:pointer;white-space:nowrap;
    transition:all .15s;position:relative;margin-bottom:2px}
  .nav-item:hover{background:var(--emerald-50);color:var(--emerald-dark)}
  .nav-item.active{background:var(--emerald-light);color:var(--emerald-dark);font-weight:600}
  .nav-item svg{width:20px;height:20px;flex-shrink:0}
  .nav-item span{transition:opacity .2s}
  .sidebar.collapsed .nav-item span{opacity:0;pointer-events:none}
  .nav-item .badge{margin-left:auto;background:var(--emerald);color:#fff;font-size:.7rem;
    padding:1px 7px;border-radius:10px;font-weight:600}
  .sidebar.collapsed .nav-item .badge{display:none}
  .sidebar-toggle{padding:12px 16px;border-top:1px solid var(--border);display:flex;
    align-items:center;gap:10px;white-space:nowrap}
  .sidebar-toggle svg{width:20px;height:20px;color:var(--text-muted);transition:transform .25s}
  .sidebar.collapsed .sidebar-toggle svg{transform:rotate(180deg)}
  .sidebar-toggle span{transition:opacity .2s}
  .sidebar.collapsed .sidebar-toggle span{opacity:0;pointer-events:none}

  /* MAIN */
  .main{margin-left:var(--sidebar-w);transition:margin-left .25s ease;min-height:100vh}
  .main.expanded{margin-left:var(--sidebar-collapsed)}

  /* TOPBAR */
  .topbar{height:var(--topbar-h);display:flex;align-items:center;justify-content:space-between;
    padding:0 24px;background:var(--surface);border-bottom:1px solid var(--border);position:sticky;top:0;z-index:50}
  .topbar-left{display:flex;align-items:center;gap:16px}
  .topbar-left h1{font-size:1.05rem;font-weight:600}
  .env-switch{display:flex;background:var(--bg);border-radius:var(--radius-sm);padding:3px;gap:2px}
  .env-btn{padding:5px 14px;border-radius:5px;font-size:.8rem;font-weight:500;
    color:var(--text-secondary);transition:all .15s}
  .env-btn:hover{color:var(--text)}
  .env-btn.active{background:var(--surface);color:var(--emerald-dark);
    box-shadow:0 1px 3px rgba(0,0,0,.08);font-weight:600}
  .topbar-right{display:flex;align-items:center;gap:12px}
  .date-picker{display:flex;align-items:center;gap:8px}
  .date-picker label{font-size:.8rem;color:var(--text-muted);font-weight:500}
  .date-picker input[type="date"]{padding:6px 10px;border:1px solid var(--border);
    border-radius:var(--radius-sm);font-size:.8rem;background:var(--surface)}
  .date-picker input[type="date"]:focus{outline:none;border-color:var(--emerald);
    box-shadow:0 0 0 3px rgba(16,185,129,.15)}
  .date-sep{color:var(--text-muted);font-size:.8rem}
  .refresh-btn{display:flex;align-items:center;gap:6px;padding:6px 14px;
    background:var(--emerald);color:#fff;border-radius:var(--radius-sm);font-size:.8rem;font-weight:600;
    transition:background .15s}
  .refresh-btn:hover{background:var(--emerald-dark)}
  .refresh-btn svg{width:14px;height:14px}

  /* CONTENT */
  .content{padding:24px}

  /* KPI STRIP */
  .kpi-strip{display:grid;grid-template-columns:repeat(4,1fr);gap:16px;margin-bottom:24px}
  .kpi-card{background:var(--surface);border:1px solid var(--border);border-radius:var(--radius);
    padding:18px 20px;display:flex;flex-direction:column;gap:4px;transition:box-shadow .15s}
  .kpi-card:hover{box-shadow:0 2px 12px rgba(0,0,0,.06)}
  .kpi-label{font-size:.78rem;color:var(--text-muted);font-weight:500;text-transform:uppercase;letter-spacing:.04em}
  .kpi-value{font-size:1.7rem;font-weight:700;color:var(--text);line-height:1.2}
  .kpi-sub{font-size:.78rem;color:var(--text-secondary);display:flex;align-items:center;gap:4px;margin-top:2px}
  .kpi-sub .up{color:var(--red)}
  .kpi-sub .down{color:var(--emerald)}
  .sparkline-wrap{margin-top:8px;height:32px}
  .sparkline-wrap svg{width:100%;height:100%}

  /* CHART */
  .chart-section{background:var(--surface);border:1px solid var(--border);border-radius:var(--radius);
    padding:20px 24px;margin-bottom:24px}
  .chart-header{display:flex;align-items:center;justify-content:space-between;margin-bottom:16px}
  .chart-header h2{font-size:1rem;font-weight:600}
  .chart-legend{display:flex;gap:16px}
  .legend-item{display:flex;align-items:center;gap:6px;font-size:.78rem;color:var(--text-secondary)}
  .legend-dot{width:10px;height:10px;border-radius:50%}
  .chart-container{position:relative;width:100%;overflow:hidden}
  .chart-container svg{width:100%;height:auto;display:block}
  .chart-tooltip{position:absolute;pointer-events:none;background:var(--text);color:#fff;
    padding:8px 12px;border-radius:var(--radius-sm);font-size:.78rem;line-height:1.6;
    box-shadow:0 4px 12px rgba(0,0,0,.2);opacity:0;transition:opacity .12s;z-index:10;
    white-space:nowrap}
  .chart-tooltip.visible{opacity:1}

  /* TABLE */
  .table-section{background:var(--surface);border:1px solid var(--border);border-radius:var(--radius);
    overflow:hidden}
  .table-header{padding:16px 20px;border-bottom:1px solid var(--border);display:flex;
    align-items:center;justify-content:space-between}
  .table-header h2{font-size:1rem;font-weight:600}
  .table-wrap{overflow-x:auto}
  table{width:100%;border-collapse:collapse}
  thead th{padding:10px 16px;text-align:left;font-size:.75rem;font-weight:600;
    color:var(--text-muted);text-transform:uppercase;letter-spacing:.04em;
    border-bottom:1px solid var(--border);background:var(--bg);cursor:pointer;
    user-select:none;white-space:nowrap;transition:color .15s}
  thead th:hover{color:var(--emerald-dark)}
  thead th .sort-icon{display:inline-block;margin-left:4px;opacity:.4;font-size:.65rem;
    transition:opacity .15s}
  thead th.sorted .sort-icon{opacity:1;color:var(--emerald)}
  tbody tr{border-bottom:1px solid var(--border);transition:background .1s}
  tbody tr:last-child{border-bottom:none}
  tbody tr:hover{background:var(--emerald-50)}
  tbody td{padding:12px 16px;font-size:.85rem;white-space:nowrap}
  .service-name{display:flex;align-items:center;gap:8px;font-weight:500}
  .service-icon{width:28px;height:28px;border-radius:var(--radius-sm);
    display:flex;align-items:center;justify-content:center;font-size:.7rem;font-weight:700;
    color:#fff;flex-shrink:0}
  .status-pill{display:inline-flex;align-items:center;gap:5px;padding:3px 10px;
    border-radius:20px;font-size:.75rem;font-weight:600}
  .status-pill.healthy{background:var(--emerald-light);color:var(--emerald-dark)}
  .status-pill.degraded{background:var(--amber-bg);color:#b45309}
  .status-pill.critical{background:var(--red-bg);color:var(--red)}
  .status-pill.offline{background:#f1f5f9;color:var(--text-muted)}
  .status-dot{width:6px;height:6px;border-radius:50%}
  .status-pill.healthy .status-dot{background:var(--emerald)}
  .status-pill.degraded .status-dot{background:var(--amber)}
  .status-pill.critical .status-dot{background:var(--red)}
  .status-pill.offline .status-dot{background:var(--text-muted)}
  .deploy-time{color:var(--text-secondary);font-size:.8rem}

  /* Scrollbar */
  ::-webkit-scrollbar{width:6px;height:6px}
  ::-webkit-scrollbar-track{background:transparent}
  ::-webkit-scrollbar-thumb{background:var(--border);border-radius:3px}
  ::-webkit-scrollbar-thumb:hover{background:var(--text-muted)}

  @media(max-width:900px){
    .kpi-strip{grid-template-columns:repeat(2,1fr)}
  }
  @media(max-width:600px){
    .kpi-strip{grid-template-columns:1fr}
    .topbar{flex-direction:column;height:auto;padding:12px 16px;gap:8px}
  }
</style>
</head>
<body>

<!-- SIDEBAR -->
<aside class="sidebar" id="sidebar">
  <div class="sidebar-brand">
    <div class="logo">
      <svg viewBox="0 0 24 24" fill="none" stroke="#fff" stroke-width="2.5" stroke-linecap="round"><path d="M22 12h-4l-3 9L9 3l-3 9H2"/></svg>
    </div>
