  </nav>
  <button class="sidebar-toggle" id="sidebarToggle" aria-label="Toggle sidebar">
    <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><polyline points="11 17 6 12 11 7"/><polyline points="18 17 13 12 18 7"/></svg>
    <span>Collapse</span>
  </button>
</aside>

<!-- MAIN -->
<div class="main" id="main">
  <!-- TOPBAR -->
  <header class="topbar">
    <div class="topbar-left">
      <h1>Dashboard</h1>
      <div class="env-switch" id="envSwitch">
        <button class="env-btn active" data-env="prod">Production</button>
        <button class="env-btn" data-env="staging">Staging</button>
        <button class="env-btn" data-env="dev">Dev</button>
      </div>
    </div>
    <div class="topbar-right">
      <div class="date-picker">
        <label>From</label>
        <input type="date" id="dateFrom">
        <span class="date-sep">→</span>
        <label>To</label>
        <input type="date" id="dateTo">
      </div>
      <button class="refresh-btn" id="refreshBtn">
        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round"><polyline points="23 4 23 10 17 10"/><path d="M20.49 15a9 9 0 1 1-2.12-9.36L23 10"/></svg>
        Refresh
      </button>
    </div>
  </header>

  <!-- CONTENT -->
  <div class="content">
    <!-- KPI STRIP -->
    <div class="kpi-strip" id="kpiStrip">
      <div class="kpi-card">
        <div class="kpi-label">P50 Latency</div>
        <div class="kpi-value">42ms</div>
        <div class="kpi-sub"><span class="down">▼ 3.2%</span> vs last hour</div>
        <div class="sparkline-wrap" id="sparkP50"></div>
      </div>
      <div class="kpi-card">
        <div class="kpi-label">P99 Latency</div>
        <div class="kpi-value">187ms</div>
        <div class="kpi-sub"><span class="up">▲ 8.1%</span> vs last hour</div>
        <div class="sparkline-wrap" id="sparkP99"></div>
      </div>
      <div class="kpi-card">
        <div class="kpi-label">Error Rate</div>
        <div class="kpi-value">0.42%</div>
        <div class="kpi-sub"><span class="down">▼ 0.8%</span> vs last hour</div>
        <div class="sparkline-wrap" id="sparkErrors"></div>
      </div>
      <div class="kpi-card">
        <div class="kpi-label">In-Flight Requests</div>
        <div class="kpi-value">1,247</div>
        <div class="kpi-sub"><span class="up">▲ 12.4%</span> vs last hour</div>
        <div class="sparkline-wrap" id="sparkInflight"></div>
      </div>
    </div>

    <!-- CHART -->
    <div class="chart-section">
      <div class="chart-header">
        <h2>Request Latency — 24h Window</h2>
        <div class="chart-legend">
          <div class="legend-item"><span class="legend-dot" style="background:var(--emerald)"></span>P50</div>
          <div class="legend-item"><span class="legend-dot" style="background:var(--blue)"></span>P95</div>
          <div class="legend-item"><span class="legend-dot" style="background:var(--red)"></span>P99</div>
        </div>
      </div>
      <div class="chart-container" id="chartContainer">
        <div class="chart-tooltip" id="chartTooltip"></div>
      </div>
    </div>

    <!-- TABLE -->
    <div class="table-section">
      <div class="table-header">
        <h2>Service Health</h2>
      </div>
      <div class="table-wrap">
        <table id="serviceTable">
          <thead>
            <tr>
              <th data-col="name" data-type="string">Service <span class="sort-icon">▲</span></th>
              <th data-col="status" data-type="string">Status <span class="sort-icon">▲</span></th>
              <th data-col="p99" data-type="number">P99 Latency <span class="sort-icon">▲</span></th>
              <th data-col="errorRate" data-type="number">Error Rate <span class="sort-icon">▲</span></th>
              <th data-col="deploy" data-type="date">Last Deploy <span class="sort-icon">▲</span></th>
            </tr>
          </thead>
          <tbody id="serviceBody"></tbody>
        </table>
      </div>
    </div>
  </div>
</div>

<script>
// ===== DATA =====
const services = [
  {name:'API Gateway',     color:'#10b981', status:'healthy',  p99:142, errorRate:0.12, deploy:'2025-01-14 09:23'},
  {name:'User Service',    color:'#3b82f6', status:'healthy',  p99:89,  errorRate:0.08, deploy:'2025-01-13 14:07'},
  {name:'Auth Service',    color:'#8b5cf6', status:'healthy',  p99:67,  errorRate:0.03, deploy:'2025-01-14 11:45'},
  {name:'Payment Service', color:'#f59e0b', status:'degraded', p99:312, errorRate:1.24, deploy:'2025-01-14 08:12'},
  {name:'Notification',    color:'#ec4899', status:'healthy',  p99:54,  errorRate:0.05, deploy:'2025-01-12 16:30'},
  {name:'Search Service',  color:'#06b6d4', status:'healthy',  p99:178, errorRate:0.31, deploy:'2025-01-14 07:55'},
  {name:'Inventory',       color:'#84cc16', status:'critical', p99:523, errorRate:4.67, deploy:'2025-01-14 06:01'},
  {name:'Order Service',   color:'#f97316', status:'healthy',  p99:134, errorRate:0.19, deploy:'2025-01-13 22:18'},
  {name:'Cache Layer',     color:'#6366f1', status:'healthy',  p99:12,  errorRate:0.01, deploy:'2025-01-11 10:00'},
  {name:'Email Worker',    color:'#14b8a6', status:'degraded', p99:445, errorRate:2.10, deploy:'2025-01-13 19:42'},
  {name:'Analytics',       color:'#a855f7', status:'healthy',  p99:98,  errorRate:0.15, deploy:'2025-01-14 03:33'},
  {name:'CDN Proxy',       color:'#64748b', status:'offline',  p99:0,   errorRate:0,    deploy:'2025-01-10 08:00'}
];

// Generate 24h data points (one per hour)
function generateLatencyData(base, variance) {
  const data = [];
  for (let i = 0; i < 24; i++) {
    const hourFactor = Math.sin((i - 6) * Math.PI / 12) * 0.3;
    const noise = (Math.random() - 0.5) * variance;
    const spike = i === 14 ? base * 0.5 : (i === 15 ? base * 0.3 : 0);
    data.push(Math.max(10, Math.round(base + base * hourFactor + noise + spike)));
  }
  return data;
}

const p50Data = generateLatencyData(42, 10);
const p95Data = generateLatencyData(120, 30);
const p99Data = generateLatencyData(187, 50);

// Sparkline data (24 points)
const sparkP50 = generateLatencyData(42, 6);
const sparkP99 = generateLatencyData(187, 20);
const sparkErrors = Array.from({length:24}, () => +(Math.random() * 1.5 + 0.1).toFixed(2));
const sparkInflight = Array.from({length:24}, () => Math.round(800 + Math.random() * 800));

// ===== SIDEBAR TOGGLE =====
const sidebar = document.getElementById('sidebar');
const main = document.getElementById('main');
const toggle = document.getElementById('sidebarToggle');
toggle.addEventListener('click', () => {
  sidebar.classList.toggle('collapsed');
  main.classList.toggle('expanded');
  toggle.querySelector('span').textContent = sidebar.classList.contains('collapsed') ? 'Expand' : 'Collapse';
});

// Nav items
document.querySelectorAll('.nav-item').forEach(item => {
  item.addEventListener('click', () => {
    document.querySelectorAll('.nav-item').forEach(n => n.classList.remove('active'));
    item.classList.add('active');
  });
});

// ===== ENV SWITCHER =====
document.querySelectorAll('.env-btn').forEach(btn => {
  btn.addEventListener('click', () => {
    document.querySelectorAll('.env-btn').forEach(b => b.classList.remove('active'));
    btn.classList.add('active');
  });
});

// ===== DATE PICKER =====
const today = new Date();
const yesterday = new Date(today); yesterday.setDate(today.getDate() - 1);
document.getElementById('dateTo').value = today.toISOString().split('T')[0];
document.getElementById('dateFrom').value = yesterday.toISOString().split('T')[0];

// ===== REFRESH BUTTON =====
document.getElementById('refreshBtn').addEventListener('click', function() {
  const icon = this.querySelector('svg');
  icon.style.transition = 'transform .5s';
  icon.style.transform = 'rotate(360deg)';
  setTimeout(() => { icon.style.transition = ''; icon.style.transform = ''; }, 600);
});

// ===== SPARKLINES =====
function drawSparkline(containerId, data, color, fill) {
  const container = document.getElementById(containerId);
  const w = container.clientWidth || 200, h = 32, pad = 2;
  const min = Math.min(...data), max = Math.max(...data);
  const range = max - min || 1;
  const step = (w - pad * 2) / (data.length - 1);
  let pathD = '', areaD = '';
  data.forEach((v, i) => {
    const x = pad + i * step, y = pad + (1 - (v - min) / range) * (h - pad * 2);
    pathD += (i === 0 ? 'M' : 'L') + x + ',' + y;
    areaD += (i === 0 ? 'M' : 'L') + x + ',' + y;
  });
  areaD += `L${pad + (data.length - 1) * step},${h}L${pad},${h}Z`;
  container.innerHTML = `<svg viewBox="0 0 ${w} ${h}" preserveAspectRatio="none">
    <defs><linearGradient id="sg_${containerId}" x1="0" y1="0" x2="0" y2="1">
      <stop offset="0%" stop-color="${color}" stop-opacity=".25"/>
      <stop offset="100%" stop-color="${color}" stop-opacity=".02"/>
    </linearGradient></defs>
    <path d="${areaD}" fill="url(#sg_${containerId})"/>
    <path d="${pathD}" fill="none" stroke="${color}" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round"/>
  </svg>`;
}

function renderSparklines() {
  drawSparkline('sparkP50', sparkP50, '#10b981');
  drawSparkline('sparkP99', sparkP99, '#3b82f6');
  drawSparkline('sparkErrors', sparkErrors, '#ef4444');
  drawSparkline('sparkInflight', sparkInflight, '#8b5cf6');
}
renderSparklines();
window.addEventListener('resize', renderSparklines);

// ===== LINE CHART =====
function renderChart() {
  const container = document.getElementById('chartContainer');
  const tooltip = document.getElementById('chartTooltip');
  const cw = container.clientWidth;
  const margin = {top: 20, right: 20, bottom: 40, left: 50};
  const w = cw - margin.left - margin.right;
  const h = 280 - margin.top - margin.bottom;
  const svgW = cw, svgH = 280;

  const allVals = [...p50Data, ...p95Data, ...p99Data];
  const yMin = 0, yMax = Math.ceil(Math.max(...allVals) / 50) * 50 + 50;
  const xScale = i => margin.left + (i / 23) * w;
  const yScale = v => margin.top + h - ((v - yMin) / (yMax - yMin)) * h;

  function makePath(data) {
    return data.map((v, i) => {
      const x = xScale(i), y = yScale(v);
      return (i === 0 ? 'M' : 'L') + x.toFixed(1) + ',' + y.toFixed(1);
    }).join(' ');
  }

  const gridLines = [];
  const yTicks = [];
  const tickCount = 6;
  for (let i = 0; i <= tickCount; i++) {
    const val = yMin + (yMax - yMin) * (i / tickCount);
    yTicks.push(Math.round(val));
    gridLines.push(yScale(val));
  }

  let svg = `<svg viewBox="0 0 ${svgW} ${svgH}" xmlns="http://www.w3.org/2000/svg">`;

  // Grid lines
  gridLines.forEach((y, i) => {
    svg += `<line x1="${margin.left}" y1="${y}" x2="${margin.left + w}" y2="${y}" stroke="#e2e8f0" stroke-width="1"/>`;
    svg += `<text x="${margin.left - 8}" y="${y + 4}" text-anchor="end" fill="#94a3b8" font-size="11" font-family="inherit">${yTicks[i]}</text>`;
  });

  // X axis labels
  const hours = ['00:00','02:00','04:00','06:00','08:00','10:00','12:00','14:00','16:00','18:00','20:00','22:00','24:00'];
  hours.forEach((label, i) => {
    const x = xScale(i);
    svg += `<text x="${x}" y="${svgH - 6}" text-anchor="middle" fill="#94a3b8" font-size="11" font-family="inherit">${label}</text>`;
    if (i > 0) svg += `<line x1="${x}" y1="${margin.top + h}" x2="${x}" y2="${margin.top + h + 4}" stroke="#cbd5e1" stroke-width="1"/>`;
  });

  // Area fills
  const datasets = [
    {data: p99Data, color: '#ef4444', id: 'area99'},
    {data: p95Data, color: '#3b82f6', id: 'area95'},
    {data: p50Data, color: '#10b981', id: 'area50'}
  ];

  datasets.forEach(ds => {
    const pathD = makePath(ds.data);
    const areaD = pathD + ` L${xScale(23)},${yScale(yMin)} L${xScale(0)},${yScale(yMin)} Z`;
    svg += `<defs><linearGradient id="grad_${ds.id}" x1="0" y1="0" x2="0" y2="1">
      <stop offset="0%" stop-color="${ds.color}" stop-opacity=".12"/>
      <stop offset="100%" stop-color="${ds.color}" stop-opacity=".01"/>
    </linearGradient></defs>`;
    svg += `<path d="${areaD}" fill="url(#grad_${ds.id})"/>`;
  });

  // Lines
  const lineColors = ['#10b981', '#3b82f6', '#ef4444'];
  const lineDatas = [p50Data, p95Data, p99Data];
  const lineLabels = ['P50', 'P95', 'P99'];
  lineDatas.forEach((data, di) => {
    svg += `<path d="${makePath(data)}" fill="none" stroke="${lineColors[di]}" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round" class="chart-line"/>`;
    // Data points
    data.forEach((v, i) => {
      svg += `<circle cx="${xScale(i)}" cy="${yScale(v)}" r="4" fill="${lineColors[di]}" stroke="#fff" stroke-width="2" class="chart-dot" style="opacity:0;transition:opacity .15s" data-x="${xScale(i)}" data-y="${yScale(v)}"/>`;
    });
  });

  // Invisible hit areas for hover
  for (let i = 0; i < 24; i++) {
    const x = xScale(i);
    svg += `<rect x="${x - w / 48}" y="${margin.top}" width="${w / 24}" height="${h}" fill="transparent" class="chart-hit" data-index="${i}"/>`;
  }

  // Axis labels
  svg += `<text x="${svgW / 2}" y="${svgH - 0}" text-anchor="middle" fill="#64748b" font-size="11" font-family="inherit">Time (UTC)</text>`;
  svg += `<text x="14" y="${svgH / 2}" text-anchor="middle" fill="#64748b" font-size="11" font-family="inherit" transform="rotate(-90,14,${svgH / 2})">Latency (ms)</text>`;

  svg += `</svg>`;

  // Place before tooltip
  const oldSvg = container.querySelector('svg');
  if (oldSvg) oldSvg.remove();
  container.insertAdjacentHTML('afterbegin', svg);

  // Hover interactions
  const svgEl = container.querySelector('svg');
  container.querySelectorAll('.chart-hit').forEach(hit => {
    hit.addEventListener('mouseenter', (e) => {
      const idx = parseInt(hit.dataset.index);
      // Show dots
      container.querySelectorAll('.chart-dot').forEach(dot => {
        if (parseInt(dot.getAttribute('data-index') || dot.parentElement.querySelectorAll('.chart-dot').indexOf(dot)) === idx) {
          // find the right dots for this index
        }
      });
      // Show all dots at this x position
      const targetX = xScale(idx);
      container.querySelectorAll('.chart-dot').forEach(dot => {
        const dx = parseFloat(dot.getAttribute('cx'));
        if (Math.abs(dx - targetX) < 5) {
          dot.style.opacity = '1';
          dot.setAttribute('r', '5');
        }
      });
      // Draw vertical crosshair
      let crosshair = container.querySelector('.crosshair');
      if (!crosshair) {
        crosshair = document.createElementNS('http://www.w3.org/2000/svg', 'line');
        crosshair.classList.add('crosshair');
        crosshair.setAttribute('stroke', '#94a3b8');
        crosshair.setAttribute('stroke-width', '1');
        crosshair.setAttribute('stroke-dasharray', '4,3');
        crosshair.setAttribute('y1', margin.top);
        crosshair.setAttribute('y2', margin.top + h);
        svgEl.insertBefore(crosshair, svgEl.firstChild);
      }
      crosshair.setAttribute('x1', targetX);
      crosshair.setAttribute('x2', targetX);
      crosshair.style.display = '';

      // Tooltip
      const hour = String(idx).padStart(2, '0') + ':00';
      tooltip.innerHTML = `<strong>${hour} UTC</strong><br>
        <span style="color:#10b981">●</span> P50: ${p50Data[idx]}ms<br>
        <span style="color:#3b82f6">●</span> P95: ${p95Data[idx]}ms<br>
        <span style="color:#ef4444">●</span> P99: ${p99Data[idx]}ms`;
      tooltip.classList.add('visible');

      // Position tooltip
      let tx = targetX + 16;
      let ty = margin.top + 10;
      const tw = tooltip.offsetWidth;
      if (tx + tw > svgW - 10) tx = targetX - tw - 16;
      if (tx < 10) tx = 10;
      tooltip.style.left = tx + 'px';
      tooltip.style.top = ty + 'px';
    });
    hit.addEventListener('mouseleave', () => {
      container.querySelectorAll('.chart-dot').forEach(dot => { dot.style.opacity = '0'; dot.setAttribute('r', '4'); });
      const ch = container.querySelector('.crosshair');
      if (ch) ch.style.display = 'none';
      tooltip.classList.remove('visible');
    });
  });
}

renderChart();
window.addEventListener('resize', renderChart);

// ===== SERVICE TABLE =====
let sortCol = 'name', sortDir = 'asc';

function statusOrder(s) { return {healthy:0, degraded:1, critical:2, offline:3}[s] || 4; }

function renderTable() {
  const tbody = document.getElementById('serviceBody');
  const sorted = [...services].sort((a, b) => {
    let va = a[sortCol], vb = b[sortCol];
    if (sortCol === 'status') { va = statusOrder(va); vb = statusOrder(vb); }
    if (sortCol === 'p99' || sortCol === 'errorRate') { va = +va; vb = +vb; }
    if (sortCol === 'deploy') { va = new Date(va); vb = new Date(vb); }
    if (va < vb) return sortDir === 'asc' ? -1 : 1;
    if (va > vb) return sortDir === 'asc' ? 1 : -1;
    return 0;
  });

  tbody.innerHTML = sorted.map(s => {
    const initials = s.name.split(' ').map(w => w[0]).join('').substring(0, 2);
    const deployFormatted = new Date(s.deploy).toLocaleDateString('en-US', {month:'short', day:'numeric', hour:'2-digit', minute:'2-digit'});
    return `<tr>
      <td><div class="service-name"><span class="service-icon" style="background:${s.color}">${initials}</span>${s.name}</div></td>
      <td><span class="status-pill ${s.status}"><span class="status-dot"></span>${s.status.charAt(0).toUpperCase() + s.status.slice(1)}</span></td>
      <td>${s.p99 > 0 ? s.p99 + 'ms' : '—'}</td>
      <td>${s.errorRate > 0 ? s.errorRate.toFixed(2) + '%' : '—'}</td>
      <td class="deploy-time">${deployFormatted}</td>
    </tr>`;
  }).join('');
}

renderTable();

// Sortable headers
document.querySelectorAll('#serviceTable thead th').forEach(th => {
  th.addEventListener('click', () => {
    const col = th.dataset.col;
    if (sortCol === col) {
      sortDir = sortDir === 'asc' ? 'desc' : 'asc';
    } else {
      sortCol = col;
      sortDir = 'asc';
    }
    // Update header styles
    document.querySelectorAll('#serviceTable thead th').forEach(h => {
      h.classList.remove('sorted');
      h.querySelector('.sort-icon').textContent = '▲';
    });
    th.classList.add('sorted');
    th.querySelector('.sort-icon').textContent = sortDir === 'asc' ? '▲' : '▼';
    renderTable();
  });
});
</script>
</body>
