  .comp-cross{color:var(--text-muted);opacity:.4}

  /* FAQ */
  .faq-section{margin-bottom:80px;max-width:760px;margin-left:auto;margin-right:auto}
  .faq-item{border:1px solid var(--border);border-radius:var(--radius-sm);margin-bottom:12px;overflow:hidden}
  .faq-question{
    width:100%;padding:18px 24px;background:var(--bg-card);border:none;color:var(--text-primary);
    font-size:.95rem;font-weight:600;text-align:left;cursor:pointer;display:flex;
    align-items:center;justify-content:space-between;gap:16px;transition:background .2s;
    font-family:inherit;
  }
  .faq-question:hover{background:var(--bg-card-hover)}
  .faq-question:focus-visible{outline:2px solid var(--indigo);outline-offset:-2px;border-radius:var(--radius-sm)}
  .faq-chevron{transition:transform .3s;flex-shrink:0;color:var(--text-muted)}
  .faq-item.open .faq-chevron{transform:rotate(180deg)}
  .faq-answer{
    max-height:0;overflow:hidden;transition:max-height .4s cubic-bezier(.4,0,.2,1),padding .3s;
    padding:0 24px;background:var(--bg-card);
  }
  .faq-item.open .faq-answer{max-height:300px;padding:0 24px 20px}
  .faq-answer p{font-size:.9rem;color:var(--text-secondary);line-height:1.7;padding-top:4px}

  /* FOOTER */
  footer{border-top:1px solid var(--border);padding:40px 0;margin-top:40px}
  .footer-inner{display:flex;align-items:center;justify-content:space-between;flex-wrap:wrap;gap:20px}
  .footer-nav{display:flex;gap:32px;flex-wrap:wrap}
  .footer-nav a{color:var(--text-muted);text-decoration:none;font-size:.88rem;transition:color .2s}
  .footer-nav a:hover{color:var(--indigo-light)}
  .status-pill{display:flex;align-items:center;gap:8px;background:rgba(34,197,94,.08);
    border:1px solid rgba(34,197,94,.2);padding:6px 16px;border-radius:20px;font-size:.8rem;
    color:var(--success);font-weight:600}
  .status-dot{width:8px;height:8px;background:var(--success);border-radius:50%;
    animation:pulse 2s ease-in-out infinite}
  @keyframes pulse{0%,100%{opacity:1;transform:scale(1)}50%{opacity:.5;transform:scale(.85)}}
  .footer-copy{width:100%;text-align:center;margin-top:20px;padding-top:20px;
    border-top:1px solid rgba(42,42,68,.4);font-size:.8rem;color:var(--text-muted)}

  /* BG GLOW */
  .bg-glow{position:fixed;top:-200px;left:50%;transform:translateX(-50%);width:800px;height:600px;
    background:radial-gradient(ellipse,rgba(99,102,241,.06) 0%,transparent 70%);pointer-events:none;z-index:-1}
</style>
</head>
