(function(){
  const toggle = document.getElementById('billingToggle');
  const monthlyLabel = document.getElementById('monthlyLabel');
  const annualLabel = document.getElementById('annualLabel');
  const saveBadge = document.getElementById('saveBadge');
  const teamNote = document.getElementById('teamNote');
  const priceEls = document.querySelectorAll('.price-amount[data-monthly]');
  let isAnnual = false;

  function updatePrices(){
    priceEls.forEach(el => {
      const newVal = isAnnual ? el.dataset.annual : el.dataset.monthly;
      if(el.textContent === newVal) return;
      el.classList.add('animate');
      setTimeout(() => {
        el.textContent = newVal;
        el.classList.remove('animate');
      }, 250);
    });
    if(isAnnual){
      saveBadge.classList.add('show');
      teamNote.textContent = 'Billed annually — $276/user/yr';
    } else {
      saveBadge.classList.remove('show');
      teamNote.textContent = 'Billed monthly';
    }
  }

  function setBilling(annual){
    isAnnual = annual;
    toggle.classList.toggle('annual', annual);
    toggle.setAttribute('aria-checked', annual);
    monthlyLabel.classList.toggle('active', !annual);
    annualLabel.classList.toggle('active', annual);
    updatePrices();
  }

  toggle.addEventListener('click', () => setBilling(!isAnnual));
  toggle.addEventListener('keydown', e => {
    if(e.key === 'Enter' || e.key === ' '){ e.preventDefault(); setBilling(!isAnnual); }
  });

  // Comparison table collapsible groups
  document.querySelectorAll('.comp-group-header').forEach(header => {
    header.addEventListener('click', () => {
      const group = header.dataset.group;
      const isCollapsed = header.classList.toggle('collapsed');
      document.querySelectorAll(`.comp-row[data-group="${group}"]`).forEach(row => {
        row.classList.toggle('hidden', isCollapsed);
      });
    });
  });

  // FAQ accordion
  document.querySelectorAll('.faq-question').forEach(btn => {
    btn.addEventListener('click', () => {
      const item = btn.closest('.faq-item');
      const isOpen = item.classList.contains('open');
      // Close all
      document.querySelectorAll('.faq-item').forEach(i => {
        i.classList.remove('open');
        i.querySelector('.faq-question').setAttribute('aria-expanded','false');
      });
      // Open clicked if it was closed
      if(!isOpen){
        item.classList.add('open');
        btn.setAttribute('aria-expanded','true');
      }
    });
    btn.addEventListener('keydown', e => {
      if(e.key === 'Enter' || e.key === ' '){ e.preventDefault(); btn.click(); }
    });
  });
})();
</script>
</body>
</html>
