    background:#111;
    border-radius:44px;
    padding:12px;
    position:relative;
    box-shadow:
      0 0 0 2px #333,
      0 0 0 4px #1a1a1a,
      0 25px 80px rgba(0,0,0,.6),
      0 0 60px rgba(78,205,196,.07);
    animation:float 6s ease-in-out infinite;
  }
  @keyframes float{
    0%,100%{transform:translateY(0) rotate(0deg)}
    25%{transform:translateY(-8px) rotate(.3deg)}
    50%{transform:translateY(-14px) rotate(0deg)}
    75%{transform:translateY(-6px) rotate(-.2deg)}
  }
  .phone-screen{
    width:100%;height:100%;
    background:linear-gradient(175deg,#13131a 0%,#0f1a1c 50%,#121218 100%);
    border-radius:34px;
    overflow:hidden;
    position:relative;
