  /* App Content */
  .app-content{padding:16px 20px 30px}
  .app-greeting{font-size:13px;color:var(--text3);margin-bottom:4px}
  .app-title{font-size:22px;font-weight:700;margin-bottom:20px;letter-spacing:-.3px}
  .app-title .wave{display:inline-block;animation:wave 2s ease-in-out infinite}
  @keyframes wave{0%,100%{transform:rotate(0)}25%{transform:rotate(20deg)}75%{transform:rotate(-10deg)}}

  /* Breathing Indicator */
  .breathing-card{
    background:linear-gradient(135deg,rgba(78,205,196,.08),rgba(78,205,196,.03));
    border:1px solid rgba(78,205,196,.12);
    border-radius:16px;
    padding:20px;
    text-align:center;
    margin-bottom:16px;
  }
  .breathing-circle{
    width:64px;height:64px;border-radius:50%;
    background:radial-gradient(circle,rgba(78,205,196,.3),rgba(78,205,196,.05));
    border:2px solid rgba(78,205,196,.3);
    margin:0 auto 12px;
    animation:breathe 8s ease-in-out infinite;
    position:relative;
  }
  .breathing-circle::after{
    content:'';position:absolute;inset:-6px;border-radius:50%;
    border:1px solid rgba(78,205,196,.15);
    animation:breathe-ring 8s ease-in-out infinite;
  }
  @keyframes breathe{
    0%,100%{transform:scale(.7);opacity:.5}
    12.5%{transform:scale(1.15);opacity:1}
    25%{transform:scale(1.15);opacity:1}
    50%{transform:scale(1.15);opacity:1}
    62.5%{transform:scale(.7);opacity:.5}
    75%{transform:scale(.7);opacity:.5}
  }
  @keyframes breathe-ring{
    0%,100%{transform:scale(.85);opacity:.3}
    12.5%{transform:scale(1.3);opacity:.15}
    25%{transform:scale(1.3);opacity:.15}
    50%{transform:scale(1.3);opacity:.15}
    62.5%{transform:scale(.85);opacity:.3}
    75%{transform:scale(.85);opacity:.3}
  }
  .breathing-label{font-size:11px;color:var(--teal);font-weight:600;letter-spacing:.5px;text-transform:uppercase}
  .breathing-sub{font-size:10px;color:var(--text3);margin-top:2px}

  /* Mood Selector */
  .mood-section{margin-bottom:16px}
  .mood-label{font-size:12px;color:var(--text3);margin-bottom:10px;font-weight:500}
  .mood-pills{display:flex;gap:8px}
  .mood-pill{
    flex:1;height:40px;border-radius:12px;
    display:flex;align-items:center;justify-content:center;
    font-size:18px;cursor:pointer;
    background:var(--bg3);border:1px solid rgba(255,255,255,.05);
    transition:all .25s;position:relative;
  }
  .mood-pill:hover{border-color:rgba(78,205,196,.3);transform:translateY(-2px)}
  .mood-pill.active{
    background:rgba(78,205,196,.15);
    border-color:rgba(78,205,196,.3);
    box-shadow:0 4px 16px rgba(78,205,196,.15);
  }
  .mood-pill .mood-emoji{transition:transform .2s}
  .mood-pill:hover .mood-emoji{transform:scale(1.2)}
  .mood-pill.active .mood-emoji{transform:scale(1.25)}

  /* Reflection Input */
  .reflection-input{
    background:var(--bg3);
    border:1px solid rgba(255,255,255,.06);
    border-radius:14px;
    padding:14px 16px;
    margin-bottom:16px;
    transition:border-color .25s;
  }
  .reflection-input:focus-within{border-color:rgba(78,205,196,.25)}
  .reflection-input label{font-size:11px;color:var(--text3);font-weight:500;display:block;margin-bottom:8px}
  .reflection-text{
    font-size:13px;color:var(--text);line-height:1.6;
    font-style:italic;
  }
  .reflection-cursor{
    display:inline-block;width:1.5px;height:16px;
    background:var(--teal);vertical-align:middle;margin-left:2px;
    animation:blink 1s step-end infinite;
  }
  @keyframes blink{0%,100%{opacity:1}50%{opacity:0}}

  /* Gratitude Section */
  .gratitude-section{margin-bottom:16px}
  .gratitude-label{font-size:12px;color:var(--text3);margin-bottom:10px;font-weight:500}
  .gratitude-item{
    display:flex;align-items:center;gap:10px;
    padding:10px 14px;
    background:var(--bg3);
    border-radius:12px;
    margin-bottom:6px;
    border:1px solid rgba(255,255,255,.04);
    font-size:12px;color:var(--text2);
  }
  .gratitude-check{
    width:18px;height:18px;border-radius:6px;
