  /* Home Indicator */
  .home-indicator{
    position:absolute;bottom:8px;left:50%;transform:translateX(-50%);
    width:120px;height:4px;border-radius:2px;background:#333;
  }

  /* ─── FEATURES ─── */
  .features{padding:120px 0}
  .section-label{
    display:inline-flex;align-items:center;gap:8px;
    font-size:13px;color:var(--teal);font-weight:600;
    letter-spacing:1px;text-transform:uppercase;
    margin-bottom:16px;
  }
  .section-label::before{content:'';width:20px;height:1.5px;background:var(--teal)}
  .section-title{font-size:40px;font-weight:800;letter-spacing:-1.5px;margin-bottom:12px}
  .section-desc{font-size:17px;color:var(--text2);max-width:520px;margin-bottom:60px;line-height:1.7}
  .features-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:24px}
