  }
  .feature-card::before{
    content:'';position:absolute;top:0;left:0;right:0;height:2px;
    background:linear-gradient(90deg,transparent,var(--teal),transparent);
    opacity:0;transition:opacity .3s;
  }
  .feature-card:hover{border-color:rgba(78,205,196,.15);transform:translateY(-4px)}
  .feature-card:hover::before{opacity:1}
  .feature-icon{
    width:52px;height:52px;border-radius:14px;
    background:var(--teal-glow2);
    border:1px solid rgba(78,205,196,.1);
    display:flex;align-items:center;justify-content:center;
    margin-bottom:20px;
  }
  .feature-icon svg{width:24px;height:24px}
  .feature-card h3{font-size:18px;font-weight:700;margin-bottom:10px;letter-spacing:-.3px}
  .feature-card p{font-size:14px;color:var(--text2);line-height:1.7}

  /* ─── WEEKLY PANEL ─── */
  .weekly{padding:80px 0 120px}
