    background:var(--bg2);
    border:1px solid rgba(255,255,255,.05);
    border-radius:20px;
    padding:40px;
    max-width:720px;
    margin:0 auto;
  }
  .weekly-header{display:flex;justify-content:space-between;align-items:center;margin-bottom:32px}
  .weekly-header h3{font-size:20px;font-weight:700;letter-spacing:-.3px}
  .weekly-header span{font-size:13px;color:var(--text3)}
  .week-grid{display:grid;grid-template-columns:repeat(7,1fr);gap:12px}
  .day-col{display:flex;flex-direction:column;align-items:center;gap:10px}
  .day-name{font-size:11px;color:var(--text3);font-weight:600;text-transform:uppercase;letter-spacing:.5px}
  .day-pill{
    width:44px;height:44px;border-radius:14px;
