    border-radius:20px;
    overflow:hidden;
    max-width:720px;
    margin:0 auto;
  }
  .pricing-card{
    padding:40px 36px;
    position:relative;
  }
  .pricing-card:first-child{border-right:1px solid rgba(255,255,255,.05)}
  .pricing-card.premium{
    background:linear-gradient(135deg,rgba(78,205,196,.06),rgba(78,205,196,.02));
  }
  .pricing-badge{
    display:inline-block;padding:4px 12px;border-radius:100px;
    font-size:11px;font-weight:700;letter-spacing:.5px;text-transform:uppercase;
    margin-bottom:16px;
  }
  .pricing-card:first-child .pricing-badge{background:var(--bg4);color:var(--text2)}
  .pricing-card.premium .pricing-badge{background:rgba(78,205,196,.15);color:var(--teal)}
  .pricing-price{font-size:36px;font-weight:800;letter-spacing:-1px;margin-bottom:4px}
  .pricing-price span{font-size:16px;font-weight:500;color:var(--text3)}
  .pricing-desc{font-size:13px;color:var(--text3);margin-bottom:24px}
  .pricing-features{list-style:none;display:flex;flex-direction:column;gap:10px;margin-bottom:28px}
  .pricing-features li{
    display:flex;align-items:center;gap:10px;
    font-size:13px;color:var(--text2);
  }
  .pricing-features li svg{width:16px;height:16px;flex-shrink:0}
  .pricing-btn{
    display:block;width:100%;padding:12px;border:none;border-radius:12px;
    font-size:14px;font-weight:600;cursor:pointer;text-align:center;
    text-decoration:none;transition:all .25s;
  }
  .pricing-card:first-child .pricing-btn{
    background:var(--bg4);color:var(--text);border:1px solid rgba(255,255,255,.08);
  }
  .pricing-card:first-child .pricing-btn:hover{border-color:var(--teal);color:var(--teal)}
  .pricing-card.premium .pricing-btn{
    background:var(--teal);color:#0e0e12;
    box-shadow:0 4px 20px rgba(78,205,196,.2);
  }
  .pricing-card.premium .pricing-btn:hover{background:#5ee0d7;transform:translateY(-1px)}

  /* ─── FOOTER ─── */
  footer{
    padding:40px 0;
    border-top:1px solid rgba(255,255,255,.04);
  }
  .footer-inner{display:flex;justify-content:space-between;align-items:center}
  .footer-left{display:flex;align-items:center;gap:10px}
  .footer-left svg{width:24px;height:24px}
  .footer-left span{font-size:16px;font-weight:700;letter-spacing:-.3px}
  .footer-links{display:flex;gap:28px}
  .footer-links a{color:var(--text3);text-decoration:none;font-size:13px;transition:color .2s}
  .footer-links a:hover{color:var(--teal)}
  .footer-copy{font-size:12px;color:var(--text3);margin-top:24px;text-align:center}

  /* ─── RESPONSIVE ─── */
  @media(max-width:900px){
    .hero .container{grid-template-columns:1fr;text-align:center}
    .hero-left{max-width:100%;display:flex;flex-direction:column;align-items:center}
    .hero h1{font-size:40px}
    .hero p{max-width:400px}
    .store-badges{justify-content:center}
    .hero-right{margin-top:40px}
    .features-grid{grid-template-columns:1fr}
    .week-grid{gap:8px}
    .day-pill{width:38px;height:38px;font-size:17px}
    .pricing-strip{grid-template-columns:1fr}
    .pricing-card:first-child{border-right:none;border-bottom:1px solid rgba(255,255,255,.05)}
    .footer-inner{flex-direction:column;gap:20px;text-align:center}
    .nav-links{display:none}
  }
</style>
</head>
