Here is the complete single-file HTML solution.

It implements a spatially uniform particle system with a custom physics loop. It handles high-DPI displays correctly, uses additive color blending for the "glow," and employs the semi-transparent clear technique for motion trails.

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Fluid Particle Swarm</title>
    <style>
        body, html {
            margin: 0;
            padding: 0;
            width: 100%;
            height: 100%;
            overflow: hidden;
            background-color: #050505; /* Near black */
        }
        canvas {
            display: block;
        }
    </style>
</head>
<body>
    <canvas id="swarmCanvas"></canvas>

    <script>
        (function() {
            const canvas = document.getElementById('swarmCanvas');
            const ctx = canvas.getContext('2d');

            // Configuration
            const PARTICLE_COUNT = 3000;
            const BASE_HUE = 200; // Cyan/Blue
            const HUE_JITTER = 40; // Range +/-
            const TRAIL_STRENGTH = 0.15; // Lower = longer trails (0.01 to 0.5)
            const MOUSE_RADIUS = 300;
            const ATTRACTION_FORCE = 0.8;
            const DAMPING = 0.92; // Friction
            const MAX_SPEED = 12;

            let width, height;
            let particles = [];

            // Mouse state
            const mouse = {
                x: -1000, // Start offscreen
                y: -1000,
                isActive: false
            };

            // Particle Class
            class Particle {
                constructor() {
                    this.init();
                }

                init() {
                    // Random position
                    this.x = Math.random() * width;
                    this.y = Math.random() * height;

                    // Random velocity
                    this.vx = (Math.random() - 0.5) * 4;
                    this.vy = (Math.random() - 0.5) * 4;

                    // Random size (small)
                    this.size = Math.random() * 2 + 0.5;

                    // Color properties
                    // HSL: Base hue + random jitter, high saturation, high lightness
                    this.hue = BASE_HUE + (Math.random() * HUE_JITTER - (HUE_JITTER / 2));
                    this.color = `hsla(${this.hue}, 80%, 60%, 1)`;
                }

                update(targetX, targetY) {
                    // Distance to target
                    const dx = targetX - this.x;
                    const dy = targetY - this.y;
                    const dist = Math.sqrt(dx * dx + dy * dy);

                    // Physics: Attraction
                    // We normalize force so it doesn't explode when very close
                    // but maintains fluid pull from far away.
                    if (dist > 0) {
                        const force = (dx / dist) * ATTRACTION_FORCE;
                        const forceY = (dy / dist) * ATTRACTION_FORCE;

                        this.vx += force;
                        this.vy += forceY;
                    }

                    // Physics: Damping (Friction)
                    this.vx *= DAMPING;
                    this.vy *= DAMPING;

                    // Clamp speed (optional, prevents infinite acceleration)
                    const speed = Math.sqrt(this.vx*this.vx + this.vy*this.vy);
                    if (speed > MAX_SPEED) {
                        const ratio = MAX_SPEED / speed;
                        this.vx *= ratio;
                        this.vy *= ratio;
                    }

                    // Update position
                    this.x += this.vx;
                    this.y += this.vy;

                    // Wrap around screen edges (Fluid wrap)
                    // This keeps particles on screen without hard bouncing
                    if (this.x < 0) this.x = width;
                    if (this.x > width) this.x = 0;
                    if (this.y < 0) this.y = height;
                    if (this.y > height) this.y = 0;
                }

                draw() {
                    ctx.beginPath();
                    ctx.arc(this.x, this.y, this.size, 0, Math.PI * 2);
                    ctx.fill();
                }
            }

            // Resize Handler
            function resize() {
                // Handle High DPI (Retina)
                const dpr = window.devicePixelRatio || 1;

                width = window.innerWidth;
                height = window.innerHeight;

                canvas.width = width * dpr;
                canvas.height = height * dpr;

                // Scale context to match CSS size
                ctx.scale(dpr, dpr);

                // Reset mouse to center if it wasn't active
                if (!mouse.isActive) {
                    mouse.x = width / 2;
                    mouse.y = height / 2;
                }
            }

            // Initialize System
            function init() {
                resize();
                particles = [];
                for (let i = 0; i < PARTICLE_COUNT; i++) {
                    particles.push(new Particle());
                }
            }

            // Animation Loop
            function animate() {
                // 1. Trail Effect
                // Instead of clearing, we draw a semi-transparent rectangle.
                // This creates the "fading tail" effect.
                ctx.globalCompositeOperation = 'source-over';
                ctx.fillStyle = `rgba(5, 5, 5, ${TRAIL_STRENGTH})`;
                ctx.fillRect(0, 0, width, height);

                // 2. Set Additive Blending
                // Overlapping particles create bright white hotspots
                ctx.globalCompositeOperation = 'lighter';

                // 3. Determine Target
                // If mouse is not active, target center
                let targetX = mouse.isActive ? mouse.x : width / 2;
                let targetY = mouse.isActive ? mouse.y : height / 2;

                // 4. Update and Draw Particles
                ctx.fillStyle = 'white'; // Base color, hue comes from logic or we can set per particle

                // Optimization: Set fillStyle once per loop if all particles shared color
                // But we have per-particle hue jitter, so we update inside loop or use batched logic.
                // For 3000 particles, setting style in loop is usually fine in modern browsers.

                for (let i = 0; i < particles.length; i++) {
                    const p = particles[i];
                    p.update(targetX, targetY);

                    // Apply per-particle color
                    ctx.fillStyle = p.color;
                    p.draw();
                }

                requestAnimationFrame(animate);
            }

            // Event Listeners
            window.addEventListener('resize', resize);

            window.addEventListener('mousemove', (e) => {
                mouse.x = e.clientX;
                mouse.y = e.clientY;
                mouse.isActive = true;
            });

            window.addEventListener('touchmove', (e) => {
                e.preventDefault(); // Prevent scrolling
                mouse.x = e.touches[0].clientX;
                mouse.y = e.touches[0].clientY;
                mouse.isActive = true;
            }, { passive: false });

            // Start
            init();
            animate();
        })();
    </script>
</body>
</html>
