    a.x = Math.random()<0.5 ? 0 : window.innerWidth;
    a.y = Math.random()*window.innerHeight;
  } else {
    a.x = Math.random()*window.innerWidth;
    a.y = Math.random()<0.5 ? 0 : window.innerHeight;
  }
  agents.push(a);
}

function respawn(a){
  var w=window.innerWidth, h=window.innerHeight;
  var e=(Math.random()*4)|0;
  if(e===0)      {a.x=0;            a.y=Math.random()*h;}
  else if(e===1) {a.x=w;            a.y=Math.random()*h;}
  else if(e===2) {a.x=Math.random()*w;a.y=0;}
  else           {a.x=Math.random()*w;a.y=h;}
}

/* ===== Main loop ===== */
var time = 0;

(function loop(){
  var w = window.innerWidth;
  var h = window.innerHeight;

  // subtle paper vignette on each frame (accumulates very faintly)
  ctx.fillStyle = 'rgba(245,240,232,0.03)';
  ctx.fillRect(0,0,w,h);

  ctx.lineWidth = 0.7;
  ctx.lineCap = 'round';
  ctx.lineJoin = 'round';

  for(var i=0;i<NUM;i++){
    var a = agents[i];

    var n = simplex2(a.x*SCALE, a.y*SCALE + time);
    var angle = n * Math.PI * 2;

    var nx = a.x + Math.cos(angle);
    var ny = a.y + Math.sin(angle);

    // warm ink variation per agent
    var brown  = (0.55 + 0.15*Math.sin(a.x*0.01+time*0.5))|0;
    var green  = (0.45 + 0.12*Math.sin(a.y*0.01+time*0.3))|0;
    var blue   = (0.35 + 0.10*Math.sin((a.x+a.y)*0.005+time*0.2))|0;
    var alpha  = 0.08 + 0.04*Math.sin(i*0.7+time*0.1);

    ctx.strokeStyle = 'rgba('+brown+','+green+','+blue+','+alpha+')';
    ctx.beginPath();
    ctx.moveTo(a.x, a.y);
    ctx.lineTo(nx, ny);
    ctx.stroke();

    a.x = nx;
    a.y = ny;

    // respawn with margin
    if(a.x<-10||a.x>w+10||a.y<-10||a.y>h+10) respawn(a);
  }

  time += TIME_SPD * 16; // ~per-frame at 60fps
  requestAnimationFrame(loop);
})();

})();
</script>
