  position: fixed; top: 0; left: 0; right: 0;
  background: #1a0000; color: #ff6666;
  font-family: monospace; font-size: 13px;
  padding: 12px 16px;
  max-height: 50vh; overflow-y: auto;
  border-bottom: 2px solid #ff0000;
  z-index: 10;
}
#error-log.visible { display: block; }
</style>
