<body>
<pre id="error-log"></pre>
<canvas id="c"></canvas>

<script>
"use strict";

const canvas = document.getElementById("c");
const errorEl = document.getElementById("error-log");

// ─── Shader sources ────────────────────────────────────────────

const VERT = `#version 300 es
precision highp float;
in vec2 a_pos;
out vec2 v_uv;
void main() {
    v_uv = a_pos * 0.5 + 0.5;
    gl_Position = vec4(a_pos, 0.0, 1.0);
}`;

const FRAG = `#version 300 es
precision highp float;
precision highp int;

in vec2 v_uv;
out vec4 fragColor;

uniform float iTime;
uniform vec2 iResolution;

// ── SDF primitives ─────────────────────────────────────────

float sdSphere(vec3 p, float r) {
    return length(p) - r;
}

float sdTorus(vec3 p, vec2 t) {
    vec2 q = vec2(length(p.xz) - t.x, p.y);
    return length(q) - t.y;
}

float opSmin(float d1, float d2, float k) {
    float h = clamp(0.5 + 0.5 * (d2 - d1) / k, 0.0, 1.0);
    return mix(d2, d1, h) - k * h * (1.0 - h);
}

// ── Scene ──────────────────────────────────────────────────

float mapSphere(vec3 p, float t) {
    float morph = sin(t * 0.5) * 0.15;
    vec3 offset = vec3(
        sin(t * 0.3) * 0.5,
        0.8 + sin(t * 0.7) * 0.2,
        cos(t * 0.4) * 0.5
    );
    return sdSphere(p - offset, 1.0 + morph);
}

float mapTorus(vec3 p, float t) {
    float morphR = 1.3 + sin(t * 0.25 + 1.0) * 0.25;
    float morphr = 0.35 + cos(t * 0.35) * 0.08;
    float angle = t * 0.15;
    float c = cos(angle), s = sin(angle);
    mat2 rot = mat2(c, -s, s, c);
    vec3 p2 = p;
    p2.xz = rot * p2.xz;
    p2.y += sin(t * 0.4) * 0.3;
    return sdTorus(p2, vec2(morphR, morphr));
}

float mapGround(vec3 p) {
    return p.y - 0.1;
}

float map(vec3 p, float t) {
    float dSphere = mapSphere(p, t);
    float dTorus  = mapTorus(p, t);
    float dUnion  = opSmin(dSphere, dTorus, 0.35);
    float dPlane  = mapGround(p);
    return min(dUnion, dPlane);
}

// ── Normal via central differences ─────────────────────────

vec3 calcNormal(vec3 p) {
    float e = 0.002;
    vec2 h = vec2(e, 0.0);
    return normalize(
        vec3(
            map(p + h.xyy, iTime) - map(p - h.xyy, iTime),
            map(p + h.yxy, iTime) - map(p - h.yxy, iTime),
            map(p + h.yyx, iTime) - map(p - h.yyx, iTime)
        ) / (2.0 * e)
    );
}

// ── Checkerboard pattern ───────────────────────────────────

float checker(vec2 p) {
    vec2 id = floor(p * 1.0);
