<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Verlet Cloth Simulation</title>
<style>
  *{margin:0;padding:0}
  html,body{width:100%;height:100%;overflow:hidden;background:#08080f}
  canvas{display:block;cursor:grab}
  canvas:active{cursor:grabbing}
</style>
</head>
<body>
<canvas id="c"></canvas>
<script>
(function(){
'use strict';

var canvas = document.getElementById('c');
var ctx = canvas.getContext('2d');

var COLS = 24, ROWS = 16;
var NUM_P = COLS * ROWS;
var GR = 0.35, DAMP = 0.996, ITER = 7, RAD = 50;

var points, conns;
var w, h, spx, spy;
var mX, mY, down, sKey, dragOX, dragOY;

function init(){
  var dpr = window.devicePixelRatio||1;
  var cw = window.innerWidth, ch = window.innerHeight;
  w = cw*dpr; h = ch*dpr;
  canvas.width = w; canvas.height = h;
  ctx.setTransform(dpr,0,0,dpr,0,0);

  spx = cw/(COLS-1);
  spy = ch*0.58/(ROWS-1);

  points = [];
  for(var i=0;i<NUM_P;i++){
    var c=i%COLS, r=i/COLS|0;
    points.push({
      x:c*spx, y:r*spy,
      px:c*spx, py:r*spy,
      pin: r===0
    });
  }

  conns = [];
  for(var r=0;r<ROWS;r++){
    for(var c=0;c<COLS;c++){
      var i = r*COLS+c;
      if(c<COLS-1){
        conns.push({a:i, b:r*COLS+c+1, on:true});
      }
      if(r<ROWS-1){
        conns.push({a:i, b:(r+1)*COLS+c, on:true});
      }
    }
  }
}

function sim(){
  var mx = mX*(w/w), my = mY*(h/h);

  for(var i=0;i<NUM_P;i++){
    var p = points[i];
    if(p.pin) continue;
    var vx = (p.x-p.px)*DAMP;
    var vy = (p.y-p.py)*DAMP;
    p.px = p.x; p.py = p.y;
    p.x += vx; p.y += vy + GR;
    var f=0;
    if(down && !sKey){
      var dx=p.x-mx, dy=p.y-my;
      var d2=dx*dx+dy*dy, r2=Rad2();
      if(d2<r2 && d2>1){
        var d=Math.sqrt(d2);
        var str=(1-d/Math.sqrt(r2))*0.75;
        f = (1-Math.abs(str));
        p.x += (mx-dragOX-p.x)*str*f;
        p.y += (my-dragOY-p.y)*str*f;
      }
    }
    if(p.y>h-4){p.y=h-4;p.py=p.y}
    if(p.x<2){p.x=2;p.py_y=p.py;p.px=p.x}
    if(p.x>w-2){p.x=w-2;p.px=p.x}
  }

  for(var it=0;it<ITER;it++){
    for(var j=0;j<conns.length;j++){
      var cn=conns[j];
      if(!cn.on) continue;
      var pa=points[cn.a], pb=points[cn.b];
      var dx=pb.x-pa.x, dy=pb.y-pa.y;
      var d2=dx*dx+dy*dy;
      if(d2<0.0001) continue;
      var d=Math.sqrt(d2);
      var dx1=dx/d, dy1=dy/d;
      var sd = Math.abs(pa.x*COLS/ROWS - (pa.x+pb.x)*0.5)/spx;
      var rest = spx*(1+sd*0.003);
      var diff=(d-rest)*0.5;
      if(pa.pin){pb.x+=dx1*diff*2;pb.y+=dy1*diff*2}
      else if(pb.pin){pa.x-=dx1*diff*2;pa.y-=dy1*diff*2}
      else{pa.x-=dx1*diff;pa.y-=dy1*diff;pb.x+=dx1*diff;pb.y+=dy1*diff}
    }
    for(var i=0;i<NUM_P;i++){
      var p=points[i];
      if(p.pin){p.x=p.px;p.y=p.py}
    }
  }
}

function Rad2(){var r=RAD*(w/window.innerWidth);return r*r}

function cutNear(mx,my){
  var cr=12*(w/window.innerWidth), cr2=cr*cr;
  var best=-1, bd=cr2;
  for(var j=0;j<conns.length;j++){
    var cn=conns[j]; if(!cn.on) continue;
    var pa=points[cn.a], pb=points[cn.b];
    var dx=pb.x-pa.x, dy=pb.y-pa.y;
    var l2=dx*dx+dy*dy; if(l2<0.01) continue;
    var nx=mx-pa.x, ny=my-pa.y;
    var t=Math.max(0,Math.min(1,(nx*dx+ny*dy)/l2));
    var px=pa.x+t*dx, py=pa.y+t*dy;
    var d2=(px-mx)*(px-mx)+(py-my)*(py-my);
    if(d2<bd){bd=d2;best=j}
  }
  if(best>=0) conns[best].on=false;
}

function render(){
  var cw=window.innerWidth, ch=window.innerHeight;
  ctx.clearRect(0,0,cw,ch);
  var bg=ctx.createLinearGradient(0,0,0,ch);
  bg.addColorStop(0,'#0a0a18');
  bg.addColorStop(1,'#06060e');
  ctx.fillStyle=bg;
