<script>
(function(){
  "use strict";

  /* ─── config ─── */
  var BARS       = 64;
  var FFT        = 1024;
  var BAR_GAP    = 0.06;       // radians gap between bars
  var BAR_WIDTH  = 0.028;      // radians visual bar width
  var BASE_PCT   = 0.07;       // base ring radius as fraction of min dimension
  var BAR_MAX_PCT= 0.32;       // max bar length as fraction of min dimension
  var SMOOTH     = 0.18;       // bar smoothing (lower = slower)
  var BASS_SMOOTH= 0.12;       // bass smoothing
  var BASS_BOOST = 1.6;        // bass punch multiplier
  var BASS_SCALE = 0.12;       // max scale oscillation
  var GLOW_BLUR  = 12;         // canvas shadowBlur for glow
  var FALLBACK_FREQ=1.0;       // Hz for fallback sine

  /* ─── state ─── */
  var canvas, ctx, dpr;
  var actx, analyser, micStream;
  var dataArr, freqArr;
  var smoothBars = [];
  var smoothBass = 0;
  var fallback = false;
  var started  = false;
  var w, h, cx, cy, radius;
  var t = 0;

  /* ─── init arrays ─── */
  for(var i=0;i<BARS;i++) smoothBars[i]=0;

  /* ─── DOM refs ─── */
  var overlay = document.getElementById('overlay');

  /* ─── resize ─── */
  function resize(){
    dpr = window.devicePixelRatio||1;
    canvas = document.getElementById('c');
    w = window.innerWidth;
    h = window.innerHeight;
    canvas.width  = w*dpr;
    canvas.height = h*dpr;
    ctx = canvas.getContext('2d');
    ctx.setTransform(dpr,0,0,dpr,0,0);
    cx = w/2;
    cy = h/2;
    radius = Math.min(w,h)*BASE_PCT;
  }
  window.addEventListener('resize', resize);
  resize();

  /* ─── user gesture → start audio ─── */
  overlay.addEventListener('click', begin);
  overlay.addEventListener('touchend', function(e){ e.preventDefault(); begin(); });

  function begin(){
    if(started) return;
    started = true;

    try{
      actx = new (window.AudioContext||window.webkitAudioContext)();
      analyser = actx.createAnalyser();
      analyser.fftSize = FFT;
      analyser.smoothingTimeConstant = 0.75;

      dataArr = new Uint8Array(analyser.frequencyBinCount);
      freqArr = new Uint8Array(analyser.frequencyBinCount);

      navigator.mediaDevices.getUserMedia({audio:true})
        .then(function(stream){
          micStream = stream;
          var src = actx.createMediaStreamSource(stream);
          src.connect(analyser);
          fallback = false;
        })
        .catch(function(){
          setupFallback();
        });
    }catch(e){
      setupFallback();
    }

    overlay.classList.add('hidden');
    requestAnimationFrame(loop);
  }

