  function setupFallback(){
    fallback = true;
    if(!actx) actx = new (window.AudioContext||window.webkitAudioContext)();
    if(actx.state==='suspended') actx.resume();
    if(!analyser){
      analyser = actx.createAnalyser();
      analyser.fftSize = FFT;
      analyser.smoothingTimeConstant = 0.75;
      dataArr = new Uint8Array(analyser.frequencyBinCount);
      freqArr = new Uint8Array(analyser.frequencyBinCount);
    }
    // 1 Hz sine
    var osc = actx.createOscillator();
    osc.type = 'sine';
    osc.frequency.value = FALLBACK_FREQ;
    var g = actx.createGain();
    g.gain.value = 180;
    osc.connect(g); g.connect(analyser);
    osc.start();
    // slow noise
    var bufLen = actx.sampleRate*2;
    var buf = actx.createBuffer(1, bufLen, actx.sampleRate);
    var ch = buf.getChannelData(0);
    for(var i=0;i<bufLen;i++) ch[i]=(Math.random()*2-1);
    var ns = actx.createBufferSource();
    ns.buffer = buf; ns.loop = true;
    var ng = actx.createGain();
    ng.gain.value = 60;
    ns.connect(ng); ng.connect(analyser);
    ns.start();
